import { forwardRef, useId } from "react";
import { clsx } from "clsx";
import { useRadioGroupContext } from "../../RadioGroup";
import { Label, type LabelCustomProps } from "../../Label";
import { RadioItem } from "../../RadioItem";
import * as styles from "./_RadioButtonCompact.css";

/**
 * Label configuration for the compact radio button.
 * Omits required (not applicable to individual items) and asChild (controlled internally).
 * The variant defaults to "normal" in this component.
 */
export type RadioButtonCompactLabel = Omit<
  LabelCustomProps,
  "required" | "asChild"
>;

export interface RadioButtonCompactProps {
  /**
   * The value of the radio button (required for RadioGroup)
   */
  value: string;

  /**
   * The visible label configuration.
   * The variant defaults to "normal" in this component.
   */
  label: RadioButtonCompactLabel;

  /**
   * Whether this radio button is disabled
   */
  disabled?: boolean;

  /**
   * Whether to hide the focus ring on the RadioItem (parent handles focus styling)
   */
  hideFocusRing?: boolean;

  /**
   * Optional class applied to the root element
   */
  className?: string;
}

/**
 * @internal
 * A compact radio button variant used internally by RadioButtonFieldset.
 * This component is styled as a row within a list, with hover/focus states
 * on the entire row and a bottom border as divider.
 */
export const _RadioButtonCompact = forwardRef<
  HTMLInputElement,
  RadioButtonCompactProps
>(
  (
    { value, label, disabled = false, hideFocusRing = false, className },
    ref
  ) => {
    const generatedId = useId();
    const radioId = `${generatedId}-radio`;
    const labelId = `${generatedId}-label`;

    // Get state from RadioGroup context to determine if this item is checked
    const groupState = useRadioGroupContext();
    const isSelected = groupState.selectedValue === value;
    const isInvalid = groupState.isInvalid;
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || groupState.isDisabled;

    return (
      <label
        className={clsx(styles.compactContainer, className)}
        data-checked={isSelected || undefined}
        data-disabled={isDisabled || undefined}
        data-invalid={isInvalid || undefined}
      >
        <RadioItem
          ref={ref}
          value={value}
          id={radioId}
          aria-labelledby={labelId}
          disabled={disabled}
          hideFocusRing={hideFocusRing}
        />
        <Label variant="normal" {...label} id={labelId} asChild>
          <span>{label.children}</span>
        </Label>
      </label>
    );
  }
);

_RadioButtonCompact.displayName = "_RadioButtonCompact";
